const output = [];

// Vi bruger et almindeligt for-loop for at kunne bruge asynkrone (await) helpers i n8n
for (let i = 0; i < $input.all().length; i++) {
  const item = $input.all()[i];

  if (item.binary) {
    // Finder automatisk navnet på den binære fil
    const binaryKey = Object.keys(item.binary)[0];

    if (binaryKey) {
      try {
        // Hent teksten sikkert ud af den binære fil
        const buffer = await this.helpers.getBinaryDataBuffer(i, binaryKey);
        const text = buffer.toString('utf-8');

        // 1. Split ved kapitler (beholder overskriften via positive lookahead)
        const chapters = text.split(/(?=#KAPITEL\s+[IVXLCDM]+)/g);

        chapters.forEach((chapterContent) => {
          // Udtræk kapitel-nummer/bogstav (f.eks. "I" eller "IV")
          const chapterMatch = chapterContent.match(/#KAPITEL\s+([IVXLCDM]+)/);
          const currentChapter = chapterMatch ? chapterMatch[1] : "Ukendt";

          // 2. Inde i hvert kapitel splitter vi ved artikler
          const articles = chapterContent.split(/(?=##Artikel\s+\d+)/g);

          articles.forEach((articleContent) => {
            const cleanedArticle = articleContent.trim();

            // Spring over, hvis det er tomt eller kun er kapitel-overskriften uden artikel-tekst
            if (!cleanedArticle || cleanedArticle.startsWith('#KAPITEL')) return;

            // Udtræk artikel-nummer (f.eks. "1")
            const articleMatch = cleanedArticle.match(/##Artikel\s+(\d+)/);
            const articleNr = articleMatch ? parseInt(articleMatch[1]) : null;

            // 3. Tilføj til output i et "fladt" format
            output.push({
              json: {
                pageContent: cleanedArticle, // Selve teksten saksen skal klippe i
                kapitel: currentChapter,     // Eksporteres som flad variabel til Loaderen
                artikel_nr: articleNr        // Eksporteres som flad variabel til Loaderen
              }
            });
          });
        });
      } catch (error) {
         console.error("Fejl ved læsning af fil buffer:", error);
      }
    }
  }
}

return output;
